@pytest.fixture
def mock_goal_repository():
    """In-memory repository stub."""
    repo = MagicMock()
    repo.goals = {}

    def _save(goal: SavingsGoal) -> SavingsGoal:
        repo.goals[goal.id] = goal
        return goal

    def _find_by_id(goal_id: str) -> SavingsGoal:
        if goal_id not in repo.goals:
            raise GoalNotFoundError(f"Goal {goal_id} not found")
        return repo.goals[goal_id]

    def _find_all() -> list:
        return list(repo.goals.values())

    repo.save.side_effect = _save
    repo.find_by_id.side_effect = _find_by_id
    repo.find_all.side_effect = _find_all
    return repo


