class TestCreateSavingsGoal:
    def test_create_goal_returns_savings_goal_instance(self, service, valid_goal_payload):
        goal = service.create_goal(**valid_goal_payload)
        assert isinstance(goal, SavingsGoal)

    def test_create_goal_assigns_unique_id(self, service, valid_goal_payload):
        goal1 = service.create_goal(**valid_goal_payload)
        goal2 = service.create_goal(**valid_goal_payload)
        assert goal1.id != goal2.id

    def test_create_goal_stores_customer_id(self, service, valid_goal_payload):
        goal = service.create_goal(**valid_goal_payload)
        assert goal.customer_id == valid_goal_payload["customer_id"]

    def test_create_goal_stores_name(self, service, valid_goal_payload):
        goal = service.create_goal(**valid_goal_payload)
        assert goal.name == valid_goal_payload["name"]
